function search_exoneracion()
{
    var descu_exonerado=0;
    if($("#ETipoDocumento").val()!='')
    {
        var tax_t=$("#total_tax").val();
        var por_ex=$("#PorcentajeExoneracion").val();
        descu_exonerado=tax_t*(por_ex/100);
        if(descu_exonerado<0)descu_exonerado=0;
    }

    return descu_exonerado;
}

function add_invoice_item(t) {

    var nl = true;
    if (1 == count && (spositems = {}) && (itemsposicion = {}), null != t) {
        var e = 1 == Settings.item_addition ? t.item_id : count;

        positions = get("lastpositions");
        if (!positions) {
            store("lastpositions", 0);
            positions = 0;
        } else {
            positions = get("lastpositions");
        }
        if (t.id == '9r091n4') {
            t.position = 50000;
            if (spositems[e]) {
                var t = $('tr[data-item-id="9r091n4"]').closest("tr"), e = t.attr("data-item-id");
                (delete spositems[e], t.remove(), spositems.hasOwnProperty(e) || (localStorage.setItem("spositems", JSON.stringify(spositems)), loadItems()));
                var nl = false;
            }
        } else {
            if (!spositems[e]) {
                t.position = parseInt(positions) + parseInt(1);
                store("lastpositions", t.position);

            }
        }
        if (nl) {
            if (spositems['9r091n4'] || e == '9r091n4') {
                var tot = 0;
                $.each(spositems, function () {
                    su = this;
                    if (su.id != '9r091n4') {
                        l = su.row.qty, c = parseFloat(su.row.quantity), s = su.row.type, d = su.row.discount, p = su.row.code, u = su.row.name.replace(/"/g, "&#034;").replace(/'/g, "&#039;"), m = parseFloat(su.row.real_unit_price), _ = su.row.comment, g = su.row.ordered ? su.row.ordered : 0, f = d || "0", v = formatDecimal(f);
                        if (-1 !== f.indexOf("%")) {
                            var h = f.split("%");
                            isNaN(h[0]) || (v = formatDecimal(parseFloat(m * parseFloat(h[0]) / 100), 4))
                        }
                        m = formatDecimal(m - v, 4);
                        tot += m * l;
                    }
                });
                if (e == '9r091n4') {
                    console.log(tot);
                    t.row.price = tot * get("propina_rate") / 100;
                    t.row.real_unit_price = tot * get("propina_rate") / 100;
                    t.row.store_price = tot * get("propina_rate") / 100;
                }
            }
            store("lastarticle", JSON.stringify(t));
            return spositems[e] ? spositems[e].row.qty = parseFloat(spositems[e].row.qty) + 1 : spositems[e] = t, store("spositems", JSON.stringify(spositems)), loadItems(), !0
        }
    }
}

function less_invoice_item(t) {
    if (1 == count && (spositems = {}) && (itemsposicion = {}), null != t) {
        var e = 1 == Settings.item_addition ? t.item_id : count;

        if (!spositems[e]) {
            t.position = count;
        }

        store("lastarticle", JSON.stringify(t));
        if (parseFloat(spositems[e].row.qty) < 2) {
            spositems[e].row.qty = parseFloat(spositems[e].row.qty) + 1;
        }
        return spositems[e] ? spositems[e].row.qty = parseFloat(spositems[e].row.qty) - 1 : spositems[e] = t, store("spositems", JSON.stringify(spositems)), loadItems(), !0
    }
}


