function pagototal() {
    var e1 = $("#amount").val();
    var e2 = $("#amount2").val();
    var e3 = $("#amount3").val();
    var e4 = $("#amount4").val();
    var e5 = $("#shipping_method").val();
    if (e1 == 'NULL' || e1 == '' || e1 == ' ')
        e1 = 0;

    if (e2 == 'NULL' || e2 == '' || e2 == ' ')
        e2 = 0;

    if (e3 == 'NULL' || e3 == '' || e3 == ' ')
        e3 = 0;

    if (e4 == 'NULL' || e4 == '' || e4 == ' ')
        e4 = 0;

    if (e5 == 'NULL' || e5 == '' || e5 == ' ')
    e5 = null;


    $("#amount_val").val(e1);
    $("#amount_val2").val(e2);
    $("#amount_val3").val(e3);
    $("#amount_val4").val(e4);
    $("#shipping_method_val").val(e5);
    $("#cc_type_val1").val($("#pcc_type1").val());
    $("#cc_type_val2").val($("#pcc_type2").val());
    $("#cc_type_val3").val($("#pcc_type3").val());
    $("#freferencia1").val($("#fpreferencia1").val());
    $("#freferencia2").val($("#fpreferencia2").val());
    $("#freferencia3").val($("#fpreferencia3").val());
    var totalenpagos = parseFloat(e1) + parseFloat(e2) + parseFloat(e3) + parseFloat(e4);
    return totalenpagos;
}

function validacredito() {
    balanceinvo = parseFloat($("#balance_val").val());

    if ($('input[name="t_nc"]').length) {
        return true;
    }


    var e = pagototal();
    //var decuE=search_exoneracion();
    var decuE=0;
    total_paid = e;
    balanceTOT = formatMoney(e - gtotal);
    balance_val = formatDecimal(e - gtotal);
    grand_total = gtotal;
    limtCli = get("spos_limitcredit");
    balance = get("spos_customer_balance");
    limtAct = limtCli - balance;
    $('#balance').html(balanceTOT);
    if (get("enable_credit") == 1) {
        console.log(Math.sign(balance_val));
        if (Math.sign(balance_val) >= 0) {
            return true;
        } else {
            // console.log($('#shipping_method').val());
            if (limtAct >= Math.abs(balance_val) || ($('#shipping_method').val() && typeof  $('#shipping_method').val() !== "undefined")) {
                return true;
            } else {
                alert("El Cliente ha exedido su limite de credito actual de " + limtAct);
                return false;
            }
        }
    } else {
        if (Math.sign(balance_val) >= 0) {
            return true;
        } else {
            alert("Se encuentra deshabilitado el credito en el sistema");
            return false;
        }
    }

}

function chr(t) {
    return String.fromCharCode(t)
}

